export const depthToSpace: OperatorImplementation<DepthToSpaceAttributes> =
    (inferenceHandler: WebGLInferenceHandler, inputs: Tensor[], attributes: DepthToSpaceAttributes): Tensor[] => {
      validateInputs(inputs);
